parameters.jsCode:
const articles = $input.all().map((item, index) => {
  const j = item.json;
  return {
    rank: index + 1,
    title: j.title || '',
    link: j.link || '',
    publicationDate: j.isoDate || j.pubDate || '',
    source: j.creator || j.author || '',
    snippet: (j.contentSnippet || j.content || '').replace(/<[^>]+>/g, '').slice(0, 500)
  };
});

const prompt = [
  'Review these recent artificial intelligence news RSS items.',
  'Pick the single most important item for engineers and technical meetup attendees.',
  'Return only valid JSON with this exact shape:',
  '{',
  '  "topHeadline": string,',
  '  "sourceLink": string,',
  '  "publicationDate": string,',
  '  "summary": string,',
  '  "whyItMatters": string,',
  '  "tags": string[],',
  '  "relevanceScore": number',
  '}',
  '',
  'RSS items:',
  JSON.stringify(articles, null, 2)
].join('\n');

return [{ json: { articles, prompt, generatedAt: new Date().toISOString() } }];

