={{ {
  "model": "gpt-4o-mini",
  "messages": [
    {
      "role": "system",
      "content": "You are an AI news editor for software engineers. Rank headlines for technical relevance, summarize clearly, and return only valid JSON. No markdown."
    },
    {
      "role": "user",
      "content": $json.prompt
    }
  ],
  "temperature": 0.3,
  "response_format": { "type": "json_object" }
} }}

parameters.jsCode:
const ai = $json.choices?.[0]?.message?.content || '{}';
const prepared = $('Prepare AI Prompt').first().json;
let parsed;
try {
  parsed = JSON.parse(ai);
} catch (error) {
  parsed = {
    topHeadline: 'Unable to parse AI response',
    sourceLink: '',
    publicationDate: '',
    summary: ai,
    whyItMatters: 'The model response was not valid JSON. Tighten the prompt or inspect the OpenAI Briefing node output.',
    tags: ['debugging'],
    relevanceScore: 0
  };
}

return [{ json: {
  topHeadline: parsed.topHeadline || '',
  sourceLink: parsed.sourceLink || '',
  publicationDate: parsed.publicationDate || '',
  summary: parsed.summary || '',
  whyItMatters: parsed.whyItMatters || '',
  tags: Array.isArray(parsed.tags) ? parsed.tags : [],
  relevanceScore: Number(parsed.relevanceScore || 0),
  candidateCount: Array.isArray(prepared.articles) ? prepared.articles.length : 0,
  generatedAt: prepared.generatedAt
} }];
